// ── Parse Google Takeout JSON ────────────────────────────────────────────────
const fileData = $input.first().binary?.data;
if (!fileData) throw new Error('Fichier vide ou illisible');

const text = Buffer.from(fileData, 'base64').toString('utf-8');
let json;
try { json = JSON.parse(text); }
catch { throw new Error('Fichier JSON invalide'); }

let entries = [];
if (Array.isArray(json)) entries = json;
else entries = json.data ?? json.history ?? json.translations ?? [];

if (!entries.length) {
  for (const key of Object.keys(json)) {
    const val = json[key];
    if (Array.isArray(val) && val.length && typeof val[0] === 'object') {
      entries = val; break;
    }
  }
}

const cards = [];
for (const e of entries) {
  const front = (e.sourceText || e['source-text'] || '').trim();
  const back  = (e.translationText || e.translatedText || e['translated-text'] || '').trim();
  const sourceLang = (e.sourceLanguage || e.sourceLang || e['source-language'] || 'en').toLowerCase();
  const targetLang = (e.targetLanguage || e.targetLang || e['target-language'] || 'fr').toLowerCase();

  if (!front || !back || front === back) continue;
  if (front.length > 200 || back.length > 200) continue;

  cards.push({ json: { front, back, sourceLang, targetLang } });
}

console.log(`[Parse] ${cards.length} mots trouvés dans le Takeout`);
return cards;

// ── Contrôle des doublons ────────────────────────────────────────────────────
// Récupère les cartes existantes depuis l'API
const existingCards = $('API — Récupérer les cartes existantes').first().json.cards || [];

// Construit un Set des clés existantes pour lookup O(1)
const existingKeys = new Set(
  existingCards.map(c => `${c.front.toLowerCase().trim()}||${c.back.toLowerCase().trim()}`)
);

// Filtre les nouveaux mots uniquement
const allCards = $('Parser le JSON Takeout').all();
const newCards = allCards.filter(item => {
  const key = `${item.json.front.toLowerCase().trim()}||${item.json.back.toLowerCase().trim()}`;
  return !existingKeys.has(key);
});

console.log(`[Doublons] Total: ${allCards.length} | Existants: ${existingKeys.size} | Nouveaux: ${newCards.length}`);

if (newCards.length === 0) {
  console.log('[Doublons] Aucun nouveau mot — workflow terminé.');
  return [];
}

return newCards;

