const word = $('Traiter mot par mot').first().json;
const claudeResp = $input.first().json;

let context = '';
try {
  const text = claudeResp.content?.[0]?.text || '{}';
  context = JSON.parse(text).context || text.trim();
} catch {
  context = claudeResp.content?.[0]?.text?.trim() || '';
}

return [{
  json: {
    front: word.front,
    back: word.back,
    sourceLang: word.sourceLang,
    targetLang: word.targetLang,
    context: context,
    importedFrom: 'n8n_daily'
  }
}];
